What does this program print?

```cpp
#include <iostream>

class Temperature {
public:
    double celsius;
    double toFahrenheit() {
        return celsius * 9.0 / 5.0 + 32.0;
    }
};

int main() {
    Temperature t;
    t.celsius = 0.0;
    std::cout << t.toFahrenheit() << "\n";
    t.celsius = 100.0;
    std::cout << t.toFahrenheit() << "\n";
}
```
